scwin.hid_kcomcd = "DBEX";
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------   
scwin.onpageload = function () {

};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    //해운 항공 구분
    scwin.seaair = $c.data.getParameter("seaair") == null ? "S" : $c.data.getParameter("seaair");
    //Import / Export 구분
    scwin.iogb = $c.data.getParameter("iogb") == null ? "O" : $c.data.getParameter("iogb");
    today = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strCurDate = today;
    scwin.strPreDate = scwin.getLastDayFromString(today);
    scwin.f_DefaultValue();
    ed_from_dt.focus();
}

scwin.getLastDayFromString = function (yyyymmdd) {
    if (!yyyymmdd || yyyymmdd.length !== 8) return "";

    const year = Number(yyyymmdd.slice(0, 4));
    const month = Number(yyyymmdd.slice(4, 6));

    // 전달 말일 → month - 1 의 0일
    const lastDate = new Date(year, month - 1, 0);

    const y = lastDate.getFullYear();
    const m = String(lastDate.getMonth() + 1).padStart(2, '0');
    const d = String(lastDate.getDate()).padStart(2, '0');

    return `${y}${m}${d}`;
}

//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------   
scwin.f_DefaultValue = function () {
    memJson = $c.data.getMemInfo();

    console.log("### onpageload :: " + JSON.stringify(memJson));
    // disbursement.style.display = "none";

    scwin.loginEmpNo = memJson.empNo;
    scwin.loginDeptCd = memJson.lobranCd;

    rd_rptgb.setValue("1");
    lc_seaair.setValue(scwin.seaair);
    lc_iogb.setValue(scwin.iogb);

    ed_from_dt.setValue(scwin.strPreDate);
    ed_to_dt.setValue(scwin.strCurDate);

    lc_iogb2.setValue(scwin.iogb);
    ed_from_dt2.setValue(scwin.strPreDate);
    ed_to_dt2.setValue(scwin.strCurDate);

    // 내부거래처 이외에는 user 정보로 read only
    if (memJson.userClsCd != '01') {
        ed_bilgClntNo.setValue(memJson.clntNo);
        txt_bilgClntNm.setValue(memJson.clntNm);
        $c.gus.cfDisableObjects([ed_bilgClntNo, txt_bilgClntNm, img_bilgClntNo]);
        scwin.udc_clnt_onviewchangeCodeEvent();
    } else {
        $c.gus.cfEnableObjects([ed_bilgClntNo, txt_bilgClntNm, img_bilgClntNo]);
    }

    /* TEST */
    // lc_seaair.setValue("");
    // lc_iogb.setValue("A");
    // ed_from_dt.setValue("20101227");
    // ed_to_dt.setValue("20111227");
    // ed_bilgClntNo.setValue("900030");
    // scwin.f_Retrieve();
    /********/
}

scwin.f_Retrieve = function () {
    ds_condition.set("seaAir", lc_seaair.getValue());
    ds_condition.set("ioGb", lc_iogb.getValue());
    ds_condition.set("fromDt", ed_from_dt.getValue());
    ds_condition.set("toDt", ed_to_dt.getValue());
    ds_condition.set("bilgClntNo", ed_bilgClntNo.getValue());
    if (chb_upperYn.checked) {
        ds_condition.set("upperYn", "Y");
    } else {
        ds_condition.set("upperYn", "N");
    }
    ds_condition.set("dept", ed_dept.getValue());
    if (!$c.gus.cfIsAfterDate(ed_from_dt.getValue(), ed_to_dt.getValue())) {
        $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ed_from_dt.focus();
        return;
    }

    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크                                                                                                                                                                                                                                                                    
    if (!$c.gus.cfValidate([ed_from_dt, ed_to_dt])) {
        return;
    }

    if (ed_from_dt.getValue() == "" || ed_to_dt.getValue() == "") {
        $c.win.alert("Billing Date는 필수 조회 조건 입니다.");
        return false;
    }

    if (ed_bilgClntNo.getValue() == "") {
        $c.win.alert("Partner는 필수 조회 조건 입니다.");
        return false;
    }
    $c.sbm.execute(sbm_retrieve);
}

scwin.f_PopUp = function (disGubun, chgGubun) {

    var rtnList = new Array();

    switch (disGubun) {
        case "bilgClntNo":		//거래처 팝업(Customer)
            udc_clnt.setSelectId("retrieveEngClntInfo");
            udc_clnt.ilCommonPopUp(scwin.udc_clnt_callbackFunc,// XML상의 SELECT ID	                                                   							
                ed_bilgClntNo.getValue(),  // 화면에서의 ??? Code Element의	Value                                  
                txt_bilgClntNm.getValue(),       // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '5',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Partner',                 	// Title순서	                                                           
                '140,300',                      // 보여주는 각 컬럼들의 폭	                                               
                null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                'F',                            // 전체검색허용여부	("F")                                                  
                'Partner Search,Partner Code,Partner Name');


            break;

        case "dept":
            udc_dept.setSelectId("retrieveOpDeptCdInfo");
            udc_dept.ilCommonPopUp(scwin.udc_dept_callbackFunc
                , ed_dept.getValue()
                , txt_deptnm.getValue()
                , "T"
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , "F"
                , "Department,Code,Name"
                , "F"
            );

            break;

        case "Liner":
            udc_liner.setSelectId("retrieveEngClntInfo");
            udc_liner.ilCommonPopUp(scwin.udc_liner_callbackFunc,    		// XML상의 SELECT ID	                                                   							
                ed_linerCd.getValue(),        // 화면에서의 ??? Code Element의	Value                                  
                txt_linerNm.getValue(),             // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Liner Code,Liner Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Liner search,Liner Code,Liner Name');
            break;

        case "port":
            udc_port.setSelectId("retrievePortInfo");
            udc_port.ilCommonPopUp(scwin.udc_port_callbackFunc
                , ed_portCd.getValue()
                , txt_portNm.getValue()
                , chgGubun
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , "F"
                , "Port Code,Code,Name");
            break;

        case "Vessel":
            udc_vsl.setSelectId("retrieveOrdVsslInfo");
            udc_vsl.ilCommonPopUp(scwin.udc_vsl_callbackFunc,
                ed_vslcd.getValue()
                , txt_vsl.getValue()
                , chgGubun
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , "F"
                , "Vessel,Code,Name");
            break;

        default:
            break;
    }

}

scwin.udc_clnt_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgClntNo, txt_bilgClntNm);
}
scwin.udc_dept_callbackFunc = function (rtnList) {
